INSERT INTO `items` (`id`, `name`, `description`, `category`, `price`, `stock_quantity`, `image_path`) VALUES
    (1, '萬代模型 MG 144 獨角獸 正版高達模型', '高達模型，精緻還原動畫中的經典機體', 'MG', 248, 50, 'bandai-rg144-unicorn.jpg'),
    (2, 'BANDAI 高達模型 RG 144 00', 'BANDAI RG 144 00高達模型，雙爐系統設計，可動性優秀', 'RG', 126, 50, 'bandai-rg144-00.jpg'),
    (3, 'BANDAI 高達模型 RG 144 Freedom', 'BANDAI RG 144 Freedom自由高達模型，翅膀展開效果震撼', 'RG', 191, 50, 'bandai-rg144-freedom.jpg'),
    (4, 'BANDAI 高達模型 RG 144 SEED', 'BANDAI RG 144 SEED系列高達模型，經典機體重現', 'RG', 191, 50, 'bandai-rg144-seed.jpg'),
    (5, 'BANDAI 高達模型 RG 144 sinanju 新安州', 'BANDAI RG 144 sinanju新安州模型，紅色彗星再臨', 'RG', 291, 50, 'bandai-rg144-sinanju.jpg'),
    (6, 'BANDAI 高達模型 RG 144 wing gundam ew', 'BANDAI RG 144 wing gundam ew飛翼高達模型，EW版特殊設計', 'RG', 191, 50, 'bandai-rg144-wing.jpg'),
    (7, 'Bandai HG 組裝模型 - 1/144 海因托利', '來自最新鋼彈系列作品《機動戰士鋼彈：水星的魔女》，辛德雷登場！\r\n■ 零件採用卡扣式設計，組裝簡便，避免夾傷。\r\n■ 頸部和腰部的球形關節採用間距式結構，可達到前後傾斜的姿勢。\r\n■ 除了龐大的體型，還配備了幾乎與機體本身一樣高的專用武器，並具備旋轉關節。\r\n■ 左臂配備專用盾牌。盾牌的臂部可動，可向前揮動。\r\n■ 背部配備由三個噴嘴組成的背包，提供極高的機動性。', 'HG', 150, 50, '69d96560dcf8f.jpg'),
    (8, 'Premium Bandai HG 組裝模型 - 1/144 Crossbone Gundam X-0 全覆式披風《機動戰士海盜高達 GHOST》', '銀色幽靈\r\n「X-0 完全裝甲」出擊！ ！\r\n出自《機動戰士鋼彈Ghost》，X-0 完全裝甲型鋼彈首次以HG系列3D模型的形式登場。\r\n這款令人印象深刻的完全裝甲機體採用全新造型零件再現，全身塗裝也採用成型色還原。武器「蝴蝶破壞者B」也採用了全新造型。\r\n● 採用全新造型零件再現的完全裝甲機體\r\n與X-1的完全裝甲機體相比，其造型有所不同，並採用了全新造型零件。\r\n●全新造型的蝴蝶破壞者 B！\r\n可透過替換零件再現槍枝模式和劍模式兩種形態。\r\n● 豐富的武器配件！\r\n包含孔雀等武器配件，可擺出多種動作姿勢。', 'HG', 490, 50, '69d9c45de1283.jpg'),
    (9, 'Premium Bandai HG 組裝模型 - 1/144 格魯古古 (Unicorn Ver.)', '出自《機動戰士鋼彈UC》，襲擊前往梅加拉尼卡的納赫爾·阿伽瑪號的格魯古，現已推出HGUC系列拼裝模型！\r\n標誌性的「袖子」經過全新造型！還附專用光束機槍！\r\n* 特色零件和武器均採用全新造型再現！\r\n標誌性的「袖子」經過全新造型再現。也新增附帶專用光束機槍。\r\n* 新吉翁標誌採用貼紙再現！\r\n* 包含系列中出現的各種武器！\r\n包含系列中出現的各種武器，例如光束薙刀和盾牌。', 'HG', 180, 50, '69d9c5050a8f2.jpg'),
    (10, 'Bandai HG 組裝模型 - 1/144 高達Mk-Ⅱ 泰坦斯配色《機動戰士Z高達》', '■出自《機動戰士Z 鋼彈》，泰坦斯規格的黑色「鋼彈Mk-II」作為HG系列「REVIVE」的第五彈登場！\r\n■與AEUG版本一樣，可擺出多種姿勢，獨特的泰坦斯配色以成型色和貼紙完美再現！', 'HG', 133, 50, '69d9c5bf18f30.jpg'),
    (11, 'Bandai HG 組裝模型 - 1/144 高達卡利班《機動戰士高達 水星的魔女》', '出自最新鋼彈系列作品《機動戰士鋼彈：水星魔女》，鋼彈卡利伯以HG（高級）模型登場！\r\n■一體成型製程再現了胸甲和天線的虹彩光澤。\r\n■可與另售的兩套水星魔女武器展示底座組合展示。\r\n■附主武器－可變式長槍。\r\n■附白色盾形紋章。\r\n■附主機展示支架。', 'HG', 130, 50, '69d9c63723ec5.jpg'),
    (12, 'Bandai HG 組裝模型 - 1/144 乍德·德卡 珂絲專用機《機動戰士高達 馬沙之反擊》', '- 來自《機動戰士鋼彈：逆襲的夏亞》的新人類「奎絲·艾爾」駕駛的紅色機體「賈格德·多加」加入HGUC系列。\r\n- 肩關節處設有擺盪機構。\r\n- 浮游砲的浮游砲可拆卸，更換零件即可重現待機和展開狀態。\r\n- 附帶特效件，可重現浮游砲發射場景。', 'HG', 190, 50, '69d9c6bcaa0df.jpg'),
    (13, 'Premium Bandai MG 組裝模型 - 1/100 突擊自由高達 朱雀舞焰 Ver. [中國限定]《中國四大神獸Project》', '出自《機動戰士高達SEED DESTINY》。突擊自由高達以中國四神獸-朱雀特別樣式在MG系列登場\r\n   具有高級感的金屬質感配色及紅色成型色', 'MG', 860, 50, '69d9c8bc73d56.jpg'),
    (14, 'Premium Bandai MG 組裝模型 - 1/100 沙煞比 (典藏Ver.) [中國限定]《典藏 Project》', '出自《機動戰士高達 逆襲的夏亞》。Nu高達的敵對機沙扎比以傳統波浪樣式的限定顔色在MG系列登場！\r\n以傳統的浪紋為靈感，采用白色及深藍色為主的成型色，結合浪紋樣式的鏡面水貼，凸顯高級感。', 'MG', 1330, 50, '69d9ca4dde483.jpg'),
    (15, 'Bandai MG 組裝模型 - 1/100 完美高達《模型狂四郎》', '- 出自漫畫《拼裝狂四郎》的「完美高達」1/100比例MG（大師級）拼裝模型套件。\r\n- 這款特別的套件不僅完美再現了其最顯著的特徵——強化外殼，而且外殼可以拆卸和安裝。\r\n- 內部鋼彈採用了全新設計的套件，比例更接近TV動畫中的形象。\r\n- 各部份的動力管路均採用軟性材料，使其活動自如。\r\n- 附帶武器包括雙管光束槍、大型肩炮和光束劍。', 'MG', 459, 50, '69d9ca9b7d1ff.jpg'),
    (16, 'Premium Bandai MG 組裝模型 - 1/100 高達巴巴托司 玄武鎮海 Ver. [中國限定] 《中國四大神獸Project》', '出自《機動戰士高達 鐵血的奧爾芬斯》。主角機高達巴巴托斯第四形態以中國四神獸 --玄武樣式在MG系列登場！\r\n以神獸玄武為靈感，黑色和白色爲主的成型色再現玄武樣式。\r\n其中黑色采用了兩種不同質感分色，進一步提升了密度感，更加凸顯構造。', 'MG', 720, 50, '69d9cbbd07199.jpg'),
    (17, 'Bandai MG 組裝模型 - 1/100 ∀高達(Turn A)', '出自《∀鋼彈》的∀鋼彈，以MG系列第100號登場！本作對原作設計進行了深入分析和建模，旨在打造一款立體化的「Turn A鋼彈解剖圖鑑」。腿部推進器葉片的結構得以重現。胸部艙門可開合，並附白色和藍色兩種胸部十字零件。武器包括專用光束步槍、盾牌和錘子。此外，還附贈1/100比例的「羅蘭·塞哈克」和「牛」人偶。首批到貨將附贈小冊子《Gunpla ∀ (Turn Ace)》。', 'MG', 360, 50, '69d9cbeeac327.jpg'),
    (18, 'Bandai RG 組裝模型 - 1/144 沙煞比', '隆重推出1/144比例的“RG沙扎比”，擁有史上最大的機關！\r\n■ 手臂汽缸、浮游砲等武器皆忠實還原，推進器和背包更是基於現實工程研究，配備了展開機構！\r\n■ 附帶多種手型零件以及沙扎比的標誌性武器，豐富的手型零件和極高的可動範圍，讓您能夠重現動畫中的各種經典姿勢，例如雙手持武器的姿勢！', 'RG', 360, 50, '69d9cc7411d30.jpg'),
    (19, 'Bandai PG 組裝模型 - 1/60 迷惘高達紅色機《機動戰士高達SEED》', '打破了4年的沉默，PG 迎來了新成員“迷惘高達紅色機 （Red Frame)”！\r\n源自“Red Frame”的名稱，也是 PG 的典範紅色可動內骨架，各部結構相互聯動，實現了動感且靈活的可動性！\r\n肩部組件通過可拉伸的方式確保了寬廣的活動範圍\r\n肘部採用多節關節，適應了複雜的“居合”式動作\r\n腹部內置了包括雙側 Lysine Danders 在內的可動機構\r\n膝蓋的可動與裝甲連動\r\n腳踝骨架的伸縮和扭轉被再現\r\n頭部攝像頭可通過發光LED和按鈕電池（另售）點亮\r\nRed Frame 特有的武器“菊一文字”可以像真正的太刀一樣可拆分為刀身、護手和柄！\r\n刀身通過鍍鉻處理再現刃紋，刀柄上刻有“菊一文字”字樣，護手和柄頭經金色鍍層呈現精細的雕刻\r\n刀身通過釘子固定在柄上\r\n菊一文字的劍鞘可以通過新設計的懸掛單元安裝在主體上\r\n此外，還附有內部組件再現的光束步槍，重視直視窗口位的盾牌，和兩把光束刀\r\n除組裝說明書之外，還有機體詳細說明書，以及時下洸一先生的原創漫畫。', 'PG', 1469, 50, '69d9cd367e242.jpg'),
    (20, 'Premium Bandai PG 組裝模型 - 1/60 完美獨角獸高達《機動戰士高達 UC》', '', 'PG', 3689, 50, '69d9cdc2a7f94.jpg'),
    (21, 'Bandai PG Unleashed 組裝模型 - 1/60 RX-78-2 高達《Gunpla 40th Anniversary Product》', '■< 鋼彈模型進化連結系統> 採用逐步組裝流程，模擬真實機動戰士的組裝體驗。\r\n■ 將最新的高達模型技術濃縮到「組裝」、「關節」、「結構」、「外觀」和「展示」五個組裝階段，讓您體驗高達模型的進化歷程。\r\n■ 擁有鋼彈模型史上最大的插入式骨架，腿部長度約180mm。構成身體骨架的整個骨架，在鋼彈模型史上可實現最早的組裝階段。\r\n■ 擁有高達模型史上最多的可動關節，全身超過90個關節。採用核心塊機構的軀幹，採用了全新的結構，擁有40個可動關節。\r\n■ 多層桁架骨架採用金屬色注塑件和鍍層零件，打造出四種不同的金屬質感。\r\n■ 採用多種材料，包括鍍銀、霧面和鍍鉻三種二次加工工藝，以及金屬零件和新開發的蝕刻貼紙。\r\n■ 擁有鋼彈模型史上最多的艙門開啟機構。\r\n■配備全新LED燈組，可呈現各種動作場景。全新緊湊型RGB雙LED燈光系統，可實現色彩變換，並結合最大化導光效率的設計，兼顧可動性和照明效果。\r\n■1/60 比例光束劍內部安裝有微型照明單元。光束劍刃採用精心製作的成型材料，可實現逼真的漸變照明效果，彷彿光束真的從劍柄底部發出。\r\n■ 要達到照明效果，需要一顆BR435針式鋰電池（內含一節用於測試）和兩顆LR41紐扣電池（另售）。', 'PG', 2599, 50, '69d9ce5525e80.jpg'),
    (22, 'Bandai PG 組裝模型 - 1/60 高達00 Raise', '■00 Raiser 登場於最高等級的高達模型系列－PG（完美級）。\r\n■GN驅動器已預先安裝並附帶。雙肩的GN驅動器內部設有可旋轉且發光的飛輪。\r\n■GN電容器（遍佈全身8個位置：肩膀、手肘、腕部和膝部）內建全新設計的離合器機構，即使握持大型武器也不會導致手臂下垂。\r\n■內部骨架細節以全新方式完全重現。\r\n■腿部的上下擺動機構大大提升了可動性，方便擺出各種動作姿勢。\r\n■附帶四種武器，作為00 Raiser的新增武裝。\r\n■所有武器均已配備齊全。內含：58個成型零件、1張金屬貼紙、1張Tetron貼紙、1張高達水貼、1張全像貼紙及組裝說明書。', 'PG', 1999, 50, '69d9cebd60d0d.jpg'),
    (23, 'Bandai PG Unleashed 組裝模型 - 1/60 RX-78-2 高達 [星夜塗裝版] [中國限定]', '', 'PG', 8499, 50, '69d9cf17b7598.jpg'),
    (24, 'Bandai PG Unleashed 組裝模型 - 1/60 RX-78-2 高達 [偏光塗層版] [中國限定]', '', 'PG', 7999, 50, '69d9cf4feb379.jpg');
